#!/usr/bin/env python3
"""
bootstrap_g4_cd_sugar_regression.py
G4 Validation Gate: CD-Sugar Regression Test (MABE repo)

Writes: tests/test_glycan_g4_cd_regression.py (29 tests)
"""
import base64, os, sys

REPO_ROOT = os.path.dirname(os.path.abspath(__file__))

# Detect MABE repo
markers = [
    os.path.join("core", "universal_schema.py"),
    os.path.join("glycan", "parameters_v23.py"),
    os.path.join("glycan", "scorer.py"),
]
found = sum(1 for m in markers if os.path.exists(os.path.join(REPO_ROOT, m)))
if found == 0:
    parent = os.path.dirname(REPO_ROOT)
    found_p = sum(1 for m in markers if os.path.exists(os.path.join(parent, m)))
    if found_p > 0:
        REPO_ROOT = parent
    else:
        print("WARNING: Could not find MABE repo markers. Writing files to current directory anyway.")

tests_dir = os.path.join(REPO_ROOT, "tests")
os.makedirs(tests_dir, exist_ok=True)

TEST_B64 = ""

out_path = os.path.join(tests_dir, "test_glycan_g4_cd_regression.py")
content = base64.b64decode(TEST_B64)
with open(out_path, "wb") as f:
    f.write(content)
print(f"  wrote {out_path} ({len(content)} bytes)")

print()
print("G4 CD-sugar regression test installed in MABE.")
print("Run: python -m pytest tests/test_glycan_g4_cd_regression.py -v")